:root {
  color-scheme: dark;
  --relay-font-sans:
    Inter, "DM Sans", ui-sans-serif, system-ui, -apple-system, BlinkMacSystemFont, "Segoe UI", sans-serif;
  --relay-font-mono: "SF Mono", "SFMono-Regular", Consolas, "Liberation Mono", Menlo, monospace;
  --relay-bg: #0a0a09;
  --relay-chrome: #0d0d0c;
  --relay-sidebar: #11110f;
  --relay-surface: #151512;
  --relay-surface-2: #191916;
  --relay-surface-3: #20201c;
  --relay-surface-hover: #23231f;
  --relay-surface-active: #2a2925;
  --relay-popover: #181815;
  --relay-input: #121210;
  --relay-text: #f0eee7;
  --relay-text-muted: #aaa49a;
  --relay-text-subtle: #7f786e;
  --relay-text-inverse: #ffffff;
  --relay-border-soft: rgb(255 255 255 / 5%);
  --relay-border: rgb(255 255 255 / 8%);
  --relay-border-strong: rgb(255 255 255 / 14%);
  --relay-primary: #9F1D1B;
  --relay-primary-hover: #B32623;
  --relay-primary-active: #841715;
  --relay-primary-muted: rgb(159 29 27 / 14%);
  --relay-primary-text: #D96760;
  --relay-ring: #B83A34;
  --relay-info: #8fb8ff;
  --relay-info-muted: rgb(143 184 255 / 14%);
  --relay-success: #87d38b;
  --relay-success-muted: rgb(135 211 139 / 13%);
  --relay-warning: #e7c36a;
  --relay-warning-muted: rgb(231 195 106 / 14%);
  --relay-danger: #ff8f80;
  --relay-danger-muted: rgb(255 143 128 / 14%);
  --relay-info-text: #b5ccff;
  --relay-success-text: #a7dfa9;
  --relay-warning-text: #f3d78c;
  --relay-danger-text: #ffb1a7;
  --relay-radius-xs: 4px;
  --relay-radius-sm: 6px;
  --relay-radius-md: 8px;
  --relay-radius-lg: 10px;
  --relay-space-1: 4px;
  --relay-space-2: 8px;
  --relay-space-3: 12px;
  --relay-space-4: 16px;
  --relay-space-5: 20px;
  --relay-space-6: 24px;
  --relay-text-xs: 11px;
  --relay-text-sm: 12px;
  --relay-text-md: 13px;
  --relay-text-base: 14px;
  --relay-text-lg: 16px;
  --relay-text-xl: 20px;
  --relay-shadow-sm: 0 1px 2px rgb(0 0 0 / 24%);
  --relay-shadow-panel: 0 16px 48px rgb(0 0 0 / 26%);
  --relay-shadow-modal: 0 28px 90px rgb(0 0 0 / 46%);
  --relay-inset-highlight: inset 0 1px 0 rgb(255 255 255 / 5%);
  --relay-focus-ring: 0 0 0 2px var(--relay-bg), 0 0 0 4px var(--relay-ring);
  font-family: var(--relay-font-sans);
  background: var(--relay-bg);
  color: var(--relay-text);
  font-synthesis: none;
  text-rendering: optimizeLegibility;
}

* {
  box-sizing: border-box;
}

html,
body,
#root {
  width: 100%;
  height: 100%;
}

body {
  margin: 0;
  min-width: 0;
  min-height: 0;
  overflow: hidden;
  background: linear-gradient(180deg, var(--relay-chrome) 0%, var(--relay-bg) 46%);
}

button,
input,
textarea,
select {
  font: inherit;
}

button {
  min-height: 32px;
  border: 1px solid var(--relay-border);
  border-radius: var(--relay-radius-md);
  background: var(--relay-surface-2);
  color: var(--relay-text);
  padding: 0 11px;
  display: inline-flex;
  align-items: center;
  justify-content: center;
  gap: var(--relay-space-2);
  cursor: pointer;
  box-shadow: var(--relay-inset-highlight);
  transition:
    background-color 140ms ease,
    border-color 140ms ease,
    color 140ms ease,
    box-shadow 140ms ease,
    transform 90ms ease;
}

button:hover {
  border-color: var(--relay-border-strong);
  background: var(--relay-surface-hover);
}

.empty-column {
  min-height: 84px;
  border: 1px dashed var(--relay-border-strong);
  border-radius: var(--relay-radius-md);
  color: var(--relay-text-subtle);
  display: grid;
  place-items: center;
  font-size: var(--relay-text-md);
}

.ticket-card {
  position: relative;
  border: 1px solid var(--relay-border);
  border-radius: var(--relay-radius-md);
  background: var(--relay-surface-2);
  box-shadow: var(--relay-shadow-sm), var(--relay-inset-highlight);
  transition:
    border-color 140ms ease,
    background-color 140ms ease,
    box-shadow 140ms ease,
    transform 140ms ease;
}

.ticket-card:hover {
  border-color: var(--relay-border-strong);
  background: var(--relay-surface-hover);
}

.ticket-card.dragging {
  z-index: 10;
  opacity: 0.9;
  transform: rotate(1deg);
  box-shadow: var(--relay-shadow-panel);
}

.card-open {
  width: 100%;
  min-height: 0;
  display: block;
  text-align: left;
  border: 0;
  background: transparent;
  padding: 11px 38px 11px 11px;
  box-shadow: none;
}

.card-open:hover {
  background: transparent;
}

.card-title {
  margin-bottom: 6px;
  color: var(--relay-text);
  font-weight: 700;
  line-height: 1.25;
}

.card-open p {
  margin: 0;
  color: var(--relay-text-muted);
  font-size: var(--relay-text-md);
  line-height: 1.35;
}

.card-meta,
.labels,
.danger-row,
.detail-actions {
  display: flex;
  align-items: center;
  gap: var(--relay-space-2);
  flex-wrap: wrap;
}

.card-meta {
  margin-top: 10px;
}

.priority,
.run-pill,
.labels span {
  min-height: 21px;
  border: 1px solid var(--relay-border-soft);
  border-radius: 999px;
  background: var(--relay-surface-3);
  color: var(--relay-text-muted);
  padding: 3px 8px;
  display: inline-flex;
  align-items: center;
  font-size: var(--relay-text-sm);
  line-height: 1.2;
}

.git-metadata {
  min-width: 0;
  max-width: min(100%, 360px);
  min-height: 22px;
  border: 1px solid var(--relay-border-soft);
  border-radius: 999px;
  background: var(--relay-surface-3);
  color: var(--relay-text-muted);
  padding: 3px 8px;
  display: inline-flex;
  align-items: center;
  gap: 6px;
  font-size: var(--relay-text-sm);
  line-height: 1.2;
  white-space: nowrap;
}

.git-metadata svg {
  flex: 0 0 auto;
}

.git-metadata > span {
  min-width: 0;
  overflow: hidden;
  text-overflow: ellipsis;
}

.git-metadata.compact {
  max-width: 170px;
  padding-inline: 6px;
}

.git-metadata.git-loading {
  color: var(--relay-text-subtle);
}

.git-metadata.git-ready {
  border-color: color-mix(in srgb, var(--relay-success) 30%, transparent);
  background: var(--relay-success-muted);
  color: var(--relay-success-text);
}

.git-metadata.git-ready.dirty {
  border-color: color-mix(in srgb, var(--relay-warning) 36%, transparent);
  background: var(--relay-warning-muted);
  color: var(--relay-warning-text);
}

.git-metadata.git-not_git,
.git-metadata.git-missing {
  border-color: var(--relay-border-soft);
  background: color-mix(in srgb, var(--relay-surface-2) 70%, transparent);
  color: var(--relay-text-subtle);
}

.git-metadata.git-unavailable,
.git-metadata.git-error {
  border-color: color-mix(in srgb, var(--relay-danger) 34%, transparent);
  background: var(--relay-danger-muted);
  color: var(--relay-danger-text);
}

.priority.high,
.priority.urgent {
  border-color: color-mix(in srgb, var(--relay-danger) 30%, transparent);
  background: var(--relay-danger-muted);
  color: var(--relay-danger-text);
}

.priority.low {
  border-color: color-mix(in srgb, var(--relay-success) 28%, transparent);
  background: var(--relay-success-muted);
  color: var(--relay-success-text);
}

.run-pill.running,
.run-pill.blocked,
.run-pill.drafting {
  border-color: color-mix(in srgb, var(--relay-warning) 34%, transparent);
  background: var(--relay-warning-muted);
  color: var(--relay-warning-text);
}

.run-pill.completed {
  border-color: color-mix(in srgb, var(--relay-success) 34%, transparent);
  background: var(--relay-success-muted);
  color: var(--relay-success-text);
}

.run-pill.failed,
.run-pill.cancelled {
  border-color: color-mix(in srgb, var(--relay-danger) 34%, transparent);
  background: var(--relay-danger-muted);
  color: var(--relay-danger-text);
}

.labels {
  margin-top: var(--relay-space-2);
}

.drag-handle {
